  // THEME TOGGLE
  function toggleTheme() {
    var body = document.body;
    var btn = document.getElementById('themeToggleBtn');
    var isLight = body.classList.toggle('light-mode');
    btn.textContent = isLight ? '🌕' : '🌙';
    try { localStorage.setItem('sbTheme', isLight ? 'light' : 'dark'); } catch(e) {}
  }

  // Apply saved theme on load
  (function() {
    try {
      if (localStorage.getItem('sbTheme') === 'light') {
        document.body.classList.add('light-mode');
        document.addEventListener('DOMContentLoaded', function() {
          var btn = document.getElementById('themeToggleBtn');
          if (btn) btn.textContent = '🌕';
        });
      }
    } catch(e) {}
  })();

  function showPanel(id, el) {
    document.querySelectorAll('.panel').forEach(function(p) { p.classList.remove('active'); });
    document.querySelectorAll('.tab').forEach(function(t) { t.classList.remove('active'); });
    document.getElementById('panel-' + id).classList.add('active');
    if (el) el.classList.add('active');
  }

  function toggleCard(card) {
    var wasExpanded = card.classList.contains('expanded');
    document.querySelectorAll('.workout-card').forEach(function(c) { c.classList.remove('expanded'); });
    if (!wasExpanded) card.classList.add('expanded');
  }

  // SOUNDS
  var SOUNDS = {
    bell:    'data:audio/wav;base64,',
    whistle: 'data:audio/wav;base64,',
    stick:   'data:audio/wav;base64,'
  };

  var tAudioCtx = null;
  var tSoundBuffers = {};

  function getAudioCtx() {
    try {
      if (!tAudioCtx || tAudioCtx.state === 'closed') {
        tAudioCtx = new (window.AudioContext || window.webkitAudioContext)();
      }
      if (tAudioCtx && tAudioCtx.state === 'suspended') { try { tAudioCtx.resume(); } catch(e){} }
    } catch(e) {}
    return tAudioCtx;
  }

  document.addEventListener('touchstart', function() {
    try { getAudioCtx(); } catch(e) {}
  }, false);

  function tLoadSound(name, cb) {
    if (tSoundBuffers[name]) { if (cb) cb(tSoundBuffers[name]); return; }
    var ctx = getAudioCtx();
    if (!ctx) return;
    var b64 = SOUNDS[name].split(',')[1];
    var bin = atob(b64);
    var bytes = new Uint8Array(bin.length);
    for (var i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    ctx.decodeAudioData(bytes.buffer, function(buf) {
      tSoundBuffers[name] = buf;
      if (cb) cb(buf);
    }, function(e) {});
  }

  function tPreload() {
    ['bell','whistle','stick'].forEach(function(n) { tLoadSound(n); });
  }

  function tPlay(name, delay) {
    delay = delay || 0;
    var ctx = getAudioCtx();
    if (!ctx) return;
    function play(buf) {
      try {
        var src = ctx.createBufferSource();
        src.buffer = buf;
        var g = ctx.createGain();
        g.gain.value = 0.9;
        src.connect(g); g.connect(ctx.destination);
        src.start(ctx.currentTime + delay);
      } catch(e) {}
    }
    if (tSoundBuffers[name]) { play(tSoundBuffers[name]); }
    else { tLoadSound(name, play); }
  }

  function tGong(delay)    { tPlay('bell',    delay || 0); }
  function tGongTriple()   { tGong(0); tGong(0.65); tGong(1.3); }
  function tGongEnd()      { tGong(0); tGong(0.35); tGong(0.70); }
  function tWarning10()    { tPlay('stick',0); tPlay('stick',0.25); tPlay('stick',0.50); }
  function tWhistle()      { tPlay('whistle',0); }
  function tWhistleDouble(){ tPlay('whistle',0); tPlay('whistle',0.72); }

  function tCountdown(sec) {
    try {
      var ctx = getAudioCtx(); if (!ctx) return;
      var now = ctx.currentTime;
      var freq = sec === 3 ? 560 : sec === 2 ? 700 : 920;
      var dur  = sec === 1 ? 0.22 : 0.11;
      var vol  = sec === 1 ? 0.55 : 0.38;
      var o = ctx.createOscillator();
      var g = ctx.createGain();
      o.connect(g); g.connect(ctx.destination);
      o.type = 'sine'; o.frequency.value = freq;
      g.gain.setValueAtTime(vol, now);
      g.gain.exponentialRampToValueAtTime(0.001, now + dur);
      o.start(now); o.stop(now + dur + 0.05);
    } catch(e) {}
  }

  function tFinish() {
    try {
      var ctx = getAudioCtx(); if (!ctx) return;
      var now = ctx.currentTime;
      [[523,0],[659,0.28],[784,0.56],[1046,0.84]].forEach(function(pair) {
        var o = ctx.createOscillator(); var g = ctx.createGain();
        o.connect(g); g.connect(ctx.destination);
        o.type = 'sine'; o.frequency.value = pair[0];
        g.gain.setValueAtTime(0.35, now + pair[1]);
        g.gain.exponentialRampToValueAtTime(0.001, now + pair[1] + 0.7);
        o.start(now + pair[1]); o.stop(now + pair[1] + 0.8);
      });
    } catch(e) {}
  }

  // ── BOXING / TABATA TIMER ─────────────────────────────────────────────────
  var MODES = {
    boxing: { rounds:3, prep:10, work:180, rest:60  },
    tabata: { rounds:8, prep:10, work:20,  rest:10  },
    custom: { rounds:3, prep:10, work:180, rest:60  }
  };
  var tMode  = 'boxing';
  var tCfg   = { rounds:3, prep:10, work:180, rest:60 };
  var tState = { running:false, phase:'idle', round:1, secs:0, interval:null };
  var CIRC   = 2 * Math.PI * 96;

  function tEl(id) { return document.getElementById(id); }

  function tFmt(s) {
    if (s >= 60) return Math.floor(s/60) + ':' + (s%60 < 10 ? '0' : '') + (s%60);
    return s + 's';
  }

  function tTotalSecs() {
    return tCfg.prep + tCfg.rounds * (tCfg.work + tCfg.rest) - tCfg.rest;
  }

  function tFmtTotal(s) {
    var m = Math.floor(s/60), sec = s%60;
    return m + ' min' + (sec > 0 ? ' ' + sec + ' sec' : '');
  }

  function tUpdateDots() {
    var d = tEl('t-dots'); if (!d) return;
    var h = '';
    for (var i = 1; i <= tCfg.rounds; i++) {
      var col = i < tState.round ? 'var(--green-punch)' : (i === tState.round && tState.phase === 'work') ? 'var(--accent)' : '#222';
      h += '<div style="width:8px;height:8px;border-radius:50%;background:'+col+';transition:background 0.3s;"></div>';
    }
    d.innerHTML = h;
  }

  function tUpdateRing(progress, phase) {
    var ring = tEl('t-ring'); if (!ring) return;
    ring.style.strokeDashoffset = CIRC * (1 - Math.max(0, Math.min(1, progress)));
    ring.style.stroke = phase === 'prep' ? 'var(--accent2)' : phase === 'work' ? 'var(--accent)' : 'var(--blue-punch)';
  }

  function tUpdateDisplay() {
    var disp  = tEl('t-display');
    var phase = tEl('t-phase-label');
    var round = tEl('t-round-label');
    if (!disp) return;
    disp.textContent = tFmt(tState.secs);
    if (tState.phase === 'idle') {
      phase.textContent = 'EN ATTENTE'; phase.style.color = 'var(--accent2)';
      round.textContent = tCfg.rounds + ' rounds';
      tUpdateRing(1, 'work'); tUpdateDots(); return;
    }
    if (tState.phase === 'done') {
      phase.textContent = 'TERMINÉ'; phase.style.color = 'var(--green-punch)';
      disp.textContent = ''; round.textContent = tCfg.rounds + ' rounds complétés';
      tUpdateRing(0, 'rest'); return;
    }
    if (tState.phase === 'prep') {
      phase.textContent = 'PRÉPARE-TOI'; phase.style.color = 'var(--accent2)';
      round.textContent = 'Round 1 / ' + tCfg.rounds;
      tUpdateRing(tState.secs / tCfg.prep, 'prep');
    } else if (tState.phase === 'work') {
      phase.textContent = 'TRAVAIL'; phase.style.color = 'var(--accent)';
      round.textContent = 'Round ' + tState.round + ' / ' + tCfg.rounds;
      tUpdateRing(tState.secs / tCfg.work, 'work');
    } else {
      phase.textContent = 'REPOS'; phase.style.color = 'var(--blue-punch)';
      round.textContent = 'Round ' + tState.round + ' / ' + tCfg.rounds;
      tUpdateRing(tState.secs / tCfg.rest, 'rest');
    }
    tUpdateDots();
  }

  function tNextPhase() {
    if (tState.phase === 'prep') {
      tState.phase = 'work'; tState.secs = tCfg.work;
      if (tMode === 'boxing') tGong(0); else tWhistle();
    } else if (tState.phase === 'work') {
      if (tState.round >= tCfg.rounds) {
        tState.phase = 'done';
        clearInterval(tState.interval); tState.running = false;
        tEl('t-start-btn').textContent = '▶';
        if (tMode === 'boxing') tGongEnd(); else tWhistleDouble();
        setTimeout(tFinish, 900);
      } else {
        tState.phase = 'rest'; tState.secs = tCfg.rest;
        if (tMode === 'boxing') tGongEnd(); else tWhistle();
      }
    } else {
      tState.round++; tState.phase = 'work'; tState.secs = tCfg.work;
      if (tMode === 'boxing') tGong(0); else tWhistle();
    }
    tUpdateDisplay();
  }

  function tTick() {
    tState.secs--;
    if (tState.secs <= 0) { tNextPhase(); return; }
    if (tMode === 'boxing') {
      if (tState.phase === 'prep' && tState.secs <= 3) tCountdown(tState.secs);
      if (tState.phase === 'work' && tState.secs === 10) tWarning10();
    } else {
      if (tState.secs <= 3) tCountdown(tState.secs);
    }
    tUpdateDisplay();
  }

  function tStartStop() {
    try { getAudioCtx(); tPreload(); } catch(e) {}
    if (tState.phase === 'done') { tReset(); return; }
    if (tState.running) {
      clearInterval(tState.interval); tState.running = false;
      tEl('t-start-btn').textContent = '▶';
    } else {
      if (tState.phase === 'idle') {
        tState.phase = tCfg.prep > 0 ? 'prep' : 'work';
        tState.round = 1;
        tState.secs  = tCfg.prep > 0 ? tCfg.prep : tCfg.work;
      }
      if (tMode === 'boxing' && tState.phase === 'prep') tGongTriple();
      tState.running = true;
      tState.interval = setInterval(tTick, 1000);
      tEl('t-start-btn').textContent = '⏸';
      tUpdateDisplay();
    }
  }

  function tSkip() {
    if (!tState.running && tState.phase === 'idle') return;
    tState.secs = 1;
    if (!tState.running) {
      tState.phase = tCfg.prep > 0 ? 'prep' : 'work';
      tState.round = 1; tState.secs = 1; tState.running = true;
      tState.interval = setInterval(tTick, 1000);
      tEl('t-start-btn').textContent = '⏸';
    }
  }

  function tReset() {
    clearInterval(tState.interval);
    tState = { running:false, phase:'idle', round:1, secs:tCfg.prep||tCfg.work, interval:null };
    tEl('t-start-btn').textContent = '▶';
    tUpdateDisplay();
  }

  function tAdjust(key, delta) {
    if (tState.running) return;
    var mins = { rounds:1, prep:0, work:15, rest:5 };
    var maxs = { rounds:20, prep:60, work:600, rest:300 };
    tCfg[key] = Math.max(mins[key], Math.min(maxs[key], tCfg[key] + delta));
    var el = tEl('t-val-' + key); if (el) el.textContent = tCfg[key];
    var tot = tEl('t-total'); if (tot) tot.textContent = tFmtTotal(tTotalSecs());
    tReset();
  }

  function tSetMode(mode) {
    if (tState.running) return;
    tMode = mode;
    tCfg  = Object.assign({}, MODES[mode]);
    ['boxing','tabata','custom'].forEach(function(m) {
      var b = tEl('tm-btn-' + m);
      if (b) b.className = 'tab' + (m === mode ? ' active' : '');
    });
    var keys = ['rounds','prep','work','rest'];
    keys.forEach(function(k) {
      var el = tEl('t-val-' + k); if (el) el.textContent = tCfg[k];
    });
    var tot = tEl('t-total'); if (tot) tot.textContent = tFmtTotal(tTotalSecs());
    tReset();
  }

  document.addEventListener('DOMContentLoaded', function() {
    tPreload();
    var keys = ['rounds','prep','work','rest'];
    keys.forEach(function(k) {
      var el = tEl('t-val-' + k); if (el) el.textContent = tCfg[k];
    });
    var tot = tEl('t-total'); if (tot) tot.textContent = tFmtTotal(tTotalSecs());
    tUpdateDisplay();
  });
